{
  "domain_analysis": {
    "business_context": "A global logistics platform introducing real-time driver earnings transparency across three jurisdictions with fundamentally different labor classifications, regulatory regimes, and worker representation requirements. This is not a simple UI feature — it encodes compensation logic, legal compliance obligations, and labor relationship definitions into the product.",
    "bounded_context": "Driver Compensation & Earnings Visibility",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for a delivery task, calculated before bonuses, tips, or deductions. In employee jurisdictions (CA), this must meet or exceed minimum wage floors." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completion of individual deliveries, such as surge pricing, distance bonuses, or batch completion incentives." },
      { "term": "Tip", "definition": "Voluntary gratuity from the customer to the driver. Legally distinct from wages — must never be counted toward base pay or minimum wage calculations in employee jurisdictions." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings: equipment fees, insurance contributions, platform fees, tax withholdings, or penalty charges. The legality and disclosure requirements for deductions vary by jurisdiction and worker classification." },
      { "term": "Earnings Breakdown", "definition": "The itemized, real-time view of a driver's compensation components for a given period, showing base pay, bonuses, tips, and deductions separately." },
      { "term": "Worker Classification", "definition": "The legal status of a driver — employee (CA under AB5), employee equivalent (Germany), or independent contractor (Indonesia) — which determines what compensation rules, transparency obligations, and deduction constraints apply." },
      { "term": "Works Council (Betriebsrat)", "definition": "A legally mandated employee representative body in Germany with co-determination rights. Must formally approve changes to compensation display systems before they go live." },
      { "term": "Wage Transparency", "definition": "The legal obligation to disclose how compensation is calculated, what deductions are applied, and the basis for each. Required in CA; co-determined in Germany; not required in Indonesia." },
      { "term": "Net Earnings", "definition": "The final amount a driver receives after all deductions are applied to gross earnings (base pay + bonuses + tips)." },
      { "term": "Pay Period", "definition": "The time window over which earnings are aggregated for display and payment. May differ by jurisdiction and classification." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Tips must never be included in or offset against base pay calculations. They must appear as a completely separate line item in the earnings breakdown.",
      "invariant": true,
      "invariant_justification": "Commingling tips with base pay violates California labor law (Labor Code §351) and is a data integrity issue — it would misrepresent the actual compensation structure and expose the platform to class-action liability.",
      "testable_assertion": "For any earnings breakdown, assert that base_pay + per_delivery_bonus is calculated independently of tip_amount, and tip_amount appears as a distinct field that is never subtracted from or factored into base_pay."
    },
    {
      "id": "BR-2",
      "rule": "Every deduction must have a named category, a reason, and a legal basis. No 'miscellaneous' or unnamed deductions are permitted.",
      "invariant": true,
      "invariant_justification": "Unnamed deductions violate wage transparency requirements in CA and would fail works council review in Germany. Even in Indonesia where not legally required, unexplained deductions destroy driver trust and create support burden. This is a data integrity constraint — an earnings record without deduction attribution is corrupt.",
      "testable_assertion": "For every deduction line item, assert that category is non-empty, reason is non-empty, and legal_basis is non-empty."
    },
    {
      "id": "BR-3",
      "rule": "In California, the earnings breakdown must show base pay that meets or exceeds applicable minimum wage when calculated on a per-hour basis. If base pay falls below minimum wage floor after calculation, the system must flag this as a compliance violation — not silently display it.",
      "invariant": true,
      "invariant_justification": "AB5 classifies California drivers as employees. Displaying sub-minimum-wage earnings without flagging it means the platform is knowingly showing an illegal pay rate. This is a legal compliance invariant.",
      "testable_assertion": "For CA drivers, assert that if (base_pay / hours_worked) < california_minimum_wage, a compliance_violation flag is raised and the breakdown includes a minimum wage adjustment line item."
    },
    {
      "id": "BR-4",
      "rule": "In Germany, the earnings transparency feature must not be deployed to drivers until works council (Betriebsrat) approval is recorded in the system. The feature must be gated behind a jurisdiction-level approval flag.",
      "invariant": true,
      "invariant_justification": "Deploying compensation display changes without Betriebsrat approval violates the Works Constitution Act (BetrVG §87). This is not a soft preference — it is a legal precondition. Violating it exposes the company to injunctions and fines.",
      "testable_assertion": "For jurisdiction='DE', assert that feature_flag('earnings_transparency_de') is only enabled when works_council_approval.status == 'approved' and works_council_approval.date is not null."
    },
    {
      "id": "BR-5",
      "rule": "Earnings breakdown must be computed and displayed in real time (within the current active session or delivery), not only available as an end-of-period summary.",
      "invariant": false,
      "invariant_justification": "Real-time display is a product requirement and driver trust mechanism, but a VP could decide to change the refresh cadence to near-real-time (e.g., 5-minute batches) for performance reasons without corrupting the system.",
      "testable_assertion": "After a delivery is completed, the driver's earnings breakdown reflects the new delivery within the defined refresh interval."
    },
    {
      "id": "BR-6",
      "rule": "The earnings breakdown must be jurisdiction-aware: it must apply the correct worker classification, deduction rules, and transparency requirements based on the driver's operating jurisdiction — not the platform's home jurisdiction.",
      "invariant": true,
      "invariant_justification": "Applying California employee rules to an Indonesian contractor (or vice versa) is both legally wrong and operationally corrupt. The jurisdiction determines the entire compensation model. Misattribution is a system integrity failure.",
      "testable_assertion": "For a driver with jurisdiction='ID', assert that employee-specific fields (e.g., minimum_wage_check, tax_withholding) are not applied. For jurisdiction='CA', assert that they are."
    },
    {
      "id": "BR-7",
      "rule": "For independent contractors (Indonesia), deductions such as platform fees must be clearly disclosed but may be structured differently than for employees. The platform must not withhold income tax for contractors — only display gross earnings and platform-level deductions.",
      "invariant": false,
      "invariant_justification": "The specific deduction categories for contractors are a business policy decision that may change as Indonesian regulations evolve. The principle of disclosure is invariant (BR-2), but the specific structure is policy.",
      "testable_assertion": "For jurisdiction='ID', assert that no tax_withholding line item exists in deductions, and that platform_fee deductions are present and itemized."
    },
    {
      "id": "BR-8",
      "rule": "Earnings data must be displayed in the driver's local currency. No cross-currency display without explicit conversion rate shown.",
      "invariant": true,
      "invariant_justification": "Displaying earnings in the wrong currency or without conversion context is financial misinformation. A driver seeing '500' without knowing if it's USD, EUR, or IDR cannot trust the system. This is a data integrity constraint.",
      "testable_assertion": "For each earnings breakdown, assert that currency_code matches the driver's jurisdiction default currency, or if converted, that exchange_rate and original_currency are displayed."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see separate line items for base pay, per-delivery bonus, tips, and itemized deductions (including tax withholdings), with base pay reflecting at least minimum wage per hour worked"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany attempts to access the earnings transparency feature",
      "when": "The works council has NOT yet approved the feature",
      "then": "The feature is unavailable and the driver sees a message explaining it is pending approval — not an error, not a blank screen"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany attempts to access the earnings transparency feature",
      "when": "The works council HAS approved the feature",
      "then": "The driver sees the full earnings breakdown, localized in EUR, with deductions itemized per German labor disclosure requirements"
    },
    {
      "id": "AC-4",
      "given": "An independent contractor driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see gross earnings (base + bonus + tips) and platform-level deductions (e.g., platform fee), with no tax withholding line items, displayed in IDR"
    },
    {
      "id": "AC-5",
      "given": "A driver in any jurisdiction receives a tip",
      "when": "They view their earnings breakdown",
      "then": "The tip appears as a separate line item that is visibly distinct from base pay and bonuses, and base pay is unchanged whether or not a tip was received"
    },
    {
      "id": "AC-6",
      "given": "A deduction is applied to a driver's earnings",
      "when": "They view the deduction in their earnings breakdown",
      "then": "The deduction shows a category, a human-readable reason, and a legal or contractual basis"
    },
    {
      "id": "AC-7",
      "given": "A California driver's calculated base pay falls below minimum wage for hours worked",
      "when": "The earnings breakdown is generated",
      "then": "The system flags a compliance violation and includes a minimum wage adjustment line item to bring total base compensation to at least the legal minimum"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver operates across jurisdiction boundaries (e.g., starts a delivery in one jurisdiction, completes in another)",
      "expected_behavior": "The system must determine the governing jurisdiction for that delivery based on a clear rule (e.g., pickup location, driver's registered jurisdiction). This must be deterministic — never ambiguous which rules apply to a single delivery."
    },
    {
      "scenario": "A customer modifies or removes a tip after the driver has already seen it in their real-time breakdown",
      "expected_behavior": "The earnings breakdown must update to reflect the change, but the original tip and the adjustment must both be visible as separate line items — never silently disappear a tip the driver already saw. This is critical for driver trust."
    },
    {
      "scenario": "Works council approval in Germany is revoked or suspended after initial deployment",
      "expected_behavior": "The feature must be immediately disabled for German drivers. The system must support approval revocation, not just initial gating. Historical earnings data remains accessible but the real-time transparency feature is suspended."
    },
    {
      "scenario": "A California driver works zero hours in a pay period but has deductions applied (e.g., equipment rental)",
      "expected_behavior": "The minimum wage check must handle division-by-zero gracefully. Base pay is $0, hours are 0, so the per-hour check is not applicable — but deductions against zero earnings must be flagged as resulting in negative net pay."
    },
    {
      "scenario": "Indonesia changes its regulations to require pay transparency or reclassify gig workers as employees",
      "expected_behavior": "The jurisdiction configuration must be updatable without code changes. Worker classification and transparency requirements should be data-driven per jurisdiction, not hardcoded."
    },
    {
      "scenario": "A deduction exceeds the driver's gross earnings for a period, resulting in negative net earnings",
      "expected_behavior": "The system must display the negative balance transparently — never hide it or silently roll it over. The driver must understand they owe the platform or that a balance is carried forward, with clear explanation."
    },
    {
      "scenario": "Real-time earnings display shows a delivery bonus, but the bonus is later clawed back due to a customer complaint or fraud flag",
      "expected_behavior": "The clawback must appear as an explicit, separately itemized deduction with reason and basis — never as a silent adjustment to the original bonus amount."
    }
  ],

  "business_impact": {
    "financial": "High. Non-compliance with AB5 in California exposes the platform to class-action wage theft lawsuits (precedent: multi-hundred-million dollar settlements in gig economy). Works council violations in Germany can result in injunctions halting operations. Conversely, transparent earnings build driver retention, reducing the $3,000-$5,000 per-driver acquisition cost.",
    "operational": "Medium-High. This feature requires jurisdiction-aware compensation logic, real-time data pipelines per delivery, and a works council approval workflow that gates deployment. Operational complexity scales with each new jurisdiction added. The deduction attribution requirement (BR-2) may require re-engineering legacy deduction systems that use lump-sum categories.",
    "user": "High. Drivers consistently cite pay opacity as a top-3 reason for leaving platforms. Real-time earnings transparency directly addresses driver satisfaction and retention. However, if the breakdown reveals unfavorable economics (high deductions, low base pay), it could accelerate churn — the platform must be prepared for this visibility to cut both ways.",
    "risk": "High. The primary risks are: (1) legal non-compliance if jurisdiction rules are misapplied, (2) works council conflict in Germany if deployed without approval, (3) driver backlash if the transparency reveals unfavorable compensation structures the platform preferred to obscure, (4) data accuracy — showing incorrect real-time earnings is worse than showing nothing.",
    "stakeholders_affected": [
      { "group": "Drivers (CA)", "impact": "Gain legally mandated visibility into wage calculations, minimum wage compliance, and deduction itemization. Direct beneficiaries." },
      { "group": "Drivers (DE)", "impact": "Feature access gated by works council. May experience delay in receiving the feature. Once approved, gain full earnings visibility under German labor standards." },
      { "group": "Drivers (ID)", "impact": "Gain voluntary transparency into earnings and platform fees. No legal obligation, but strong trust-building value in a market where platform switching is common." },
      { "group": "Works Council (DE)", "impact": "Must be formally engaged and grant approval. This is a co-determination matter — ignoring them is not an option. They may request modifications to the display format or deduction categories." },
      { "group": "Legal & Compliance Team", "impact": "Must validate that each jurisdiction's implementation meets local requirements. Ongoing obligation as regulations change." },
      { "group": "Finance / Payroll Team", "impact": "Must ensure the real-time earnings data is consistent with actual payroll calculations. Any divergence between what drivers see and what they're paid will destroy trust and create legal liability." },
      { "group": "Product & Engineering", "impact": "Must build a jurisdiction-aware, real-time compensation display system with feature flagging, approval workflows, and extensible deduction categorization." },
      { "group": "Customers", "impact": "Indirect. Tip modification behavior (post-delivery tip changes) now has visible consequences to drivers. May affect tipping culture." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is a single sentence ('Show each driver their earnings breakdown in real time') with jurisdiction context but no detail on: (1) what specific deduction categories exist, (2) how 'real time' is defined (per-second? per-delivery completion? per-refresh?), (3) whether the works council process has begun or what their known concerns are, (4) how cross-jurisdiction drivers are handled, (5) what the current compensation model actually looks like in each market. Multiple critical domain decisions must be made that are not specified. Additionally, the German works council requirement introduces a hard external dependency that could change the feature scope entirely based on their feedback.",
    "high_confidence_areas": [
      "Tip separation from base pay is a hard legal and domain invariant (BR-1)",
      "Works council approval is a non-negotiable legal precondition in Germany (BR-4)",
      "Worker classification drives fundamentally different compensation display rules per jurisdiction (BR-6)",
      "Deductions must be attributed and explained — unnamed deductions are never acceptable (BR-2)"
    ],
    "low_confidence_areas": [
      "Exact deduction categories per jurisdiction — spec does not enumerate them",
      "Definition of 'real time' — could mean streaming, per-delivery, or periodic refresh",
      "Cross-jurisdiction delivery handling — no rule specified for which jurisdiction governs",
      "Works council's actual requirements — they may demand changes to the proposed design",
      "Whether California minimum wage adjustment should be automatic or flagged for manual review"
    ],
    "assumptions": [
      "The platform already has jurisdiction data for each driver and can determine worker classification",
      "The compensation model (base pay, bonuses, tips, deductions) exists and the feature is a visibility layer — not a new compensation system",
      "The works council engagement in Germany has not yet occurred and must be planned as a prerequisite",
      "Tips are customer-initiated and pass through the platform (not cash tips outside the system)",
      "The platform intends to comply with all local regulations, not seek exemptions or legal challenges"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define what 'real time' means. Per-second streaming, per-delivery-completion update, or periodic batch refresh have fundamentally different technical and UX implications. The choice also affects whether drivers see in-progress delivery earnings (estimated) or only completed delivery earnings (actual).",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Product & Engineering", "Finance / Payroll Team"],
      "options": [
        "Real time = earnings update immediately upon each delivery completion event",
        "Real time = earnings stream updates during an active delivery (estimated, then finalized)",
        "Real time = periodic refresh (e.g., every 5 minutes) of aggregated earnings"
      ],
      "recommendation": "Define 'real time' as per-delivery-completion actuals with a clear 'pending' state for in-progress deliveries. This balances accuracy with responsiveness and avoids showing estimated amounts that later change."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not enumerate deduction categories. The domain rules require every deduction to be categorized (BR-2), but we don't know what the valid categories are. This is jurisdiction-dependent and classification-dependent.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Legal & Compliance Team", "Finance / Payroll Team"],
      "options": [
        "Define a fixed global taxonomy of deduction categories (e.g., tax_withholding, platform_fee, insurance, equipment, penalty)",
        "Allow each jurisdiction to define its own deduction categories independently",
        "Define a core set of global categories with jurisdiction-specific extensions"
      ],
      "recommendation": "Core global categories with jurisdiction-specific extensions. This ensures consistency for platform-wide reporting while accommodating local requirements."
    },
    {
      "type": "missing_context",
      "description": "We do not know the current state of works council engagement in Germany. If the Betriebsrat has not been consulted, this feature cannot launch in Germany on any timeline. Their feedback may materially alter the feature design — they have co-determination rights over compensation display.",
      "affected_stakeholders": ["Works Council (DE)", "Drivers (DE)", "Legal & Compliance Team", "Product & Engineering"],
      "options": [
        "Launch in CA and ID first while Germany works council process runs in parallel",
        "Delay global launch until all three jurisdictions are cleared",
        "Build the feature with a Germany-specific approval gate and launch other jurisdictions independently"
      ],
      "recommendation": "Build with a jurisdiction-level feature gate from day one. Launch CA and ID when ready. Germany launches only after Betriebsrat approval. This is not optional — it is the only legally compliant path."
    },
    {
      "type": "ambiguity",
      "description": "Cross-jurisdiction delivery handling is undefined. If a driver picks up in one jurisdiction and delivers in another (or is registered in one jurisdiction but operates in another), which rules govern?",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Legal & Compliance Team"],
      "options": [
        "Governing jurisdiction = driver's registered/home jurisdiction",
        "Governing jurisdiction = pickup location of each delivery",
        "Governing jurisdiction = delivery destination"
      ],
      "recommendation": "Escalate to Legal. This is a legal determination, not a product decision. In the interim, default to the driver's registered jurisdiction as the safest assumption, since that's where their employment/contractor relationship is established."
    }
  ],

  "rejection_reasons": []
}

